    const MIN_SIZE: usize = core::mem::size_of::<CloneArgsV0>();
    const SUPPORTED_SIZE: usize = core::mem::size_of::<CloneArgs>();

    if size < MIN_SIZE {
        return Err(EINVAL);
    }
    if size > PAGE_SIZE {
        return Err(E2BIG);
    }
    if uargs.is_null() {
        return Err(EFAULT);
    }

    let copy_len = size.min(SUPPORTED_SIZE);

