    let allowed = if inner.fsuid == metadata.uid {
        (mode >> 6) & 0o7
    } else if inner.fsgid == metadata.gid || inner.groups.iter().any(|&gid| gid == metadata.gid) {
        (mode >> 3) & 0o7
    } else {
        mode & 0o7
    };

