// ─── RingBuffer ──────────────────────────────────────────────────────────

pub(crate) struct RingBuffer {
    buf: Vec<u8>,
    head: usize,
    len: usize,
}

impl RingBuffer {
    fn new(capacity: usize) -> Self {
        RingBuffer { buf: alloc::vec![0u8; capacity], head: 0, len: 0 }
    }

    fn available(&self) -> usize { self.len }

    fn free_space(&self) -> usize { self.buf.len() - self.len }

    fn clear(&mut self) { self.head = 0; self.len = 0; }

    fn write(&mut self, data: &[u8]) -> usize {
        let cap = self.buf.len();
        let n = data.len().min(cap - self.len);
        for i in 0..n {
            self.buf[(self.head + self.len + i) % cap] = data[i];
        }
        self.len += n;
        n
    }

    fn read(&mut self, out: &mut [u8]) -> usize {
        let cap = self.buf.len();
        let n = out.len().min(self.len);
        for i in 0..n {
            out[i] = self.buf[(self.head + i) % cap];
        }
        self.head = (self.head + n) % cap;
        self.len -= n;
        n
    }
}

