pub struct NetlinkSocket {
    pub protocol: u32,
    pub recv_queue: spin::Mutex<VecDeque<Vec<u8>>>,
    /// WaitQueue for blocking recv — woken when push_recv() adds data.
    pub recv_wait: Mutex<WaitQueue>,
